mapper.insert:
INSERT INTO FWK_LISTENER_CONNECTOR_MAPPING ( LISTENER_GW_ID, LISTENER_SYSTEM_ID, IDENTIFIER, CONNECTOR_GW_ID, CONNECTOR_SYSTEM_ID, DESCRIPTION ) SELECT A.* FROM (
SELECT #{item.listenerGwId} AS LISTENER_GW_ID, #{item.listenerSystemId} AS LISTENER_SYSTEM_ID, #{item.identifier} AS IDENTIFIER, #{item.connectorGwId} AS CONNECTOR_GW_ID, #{item.connectorSystemId} AS CONNECTOR_SYSTEM_ID, #{item.description} AS DESCRIPTION FROM DUAL
) A

mapper.update:
UPDATE FWK_LISTENER_CONNECTOR_MAPPING
