    CONNECTOR_GW_ID = #{dto.connectorGwId},
    CONNECTOR_SYSTEM_ID = #{dto.connectorSystemId},
    DESCRIPTION = #{dto.description}
WHERE LISTENER_GW_ID = #{listenerGwId}
  AND LISTENER_SYSTEM_ID = #{listenerSystemId}
  AND IDENTIFIER = #{identifier}

mapper.delete:
